ALTER TABLE public.cases ADD COLUMN IF NOT EXISTS note TEXT;

UPDATE public.cases
SET solution = 'OpenClaw работает через собственный пульт управления и внутренний мессенджер. Он объединяет задачи, календарь, почту, аналитику, статистику, маркетинговые гипотезы, мониторинг серверов и состояние интеграций. OpenClaw работает над всеми цифровыми направлениями владельца, включая AI My Time и проекты клиентов. Он отслеживает состояние сервисов, собирает аналитику, координирует задачи и ведёт мониторинг открытых источников по заданным ключевым словам. Перед любым критическим действием — изменением данных, внешней отправкой, перезапуском сервиса или вмешательством в процессы — OpenClaw запрашивает подтверждение владельца.',
    ecosystem_role = 'OpenClaw выступает как AI-директор и центр управления всеми проектами. Он контролирует состояние серверов, сервисов и интеграций, собирает сводки, замечает ошибки и точки внимания, помогает строить рекламные и маркетинговые стратегии, координирует задачи и поддерживает развитие бизнеса. Отдельный модуль мониторинга открытых источников выявляет релевантные упоминания и сигналы спроса по ключевым словам, формирует карточки потенциальных лидов с источником и контекстом, а затем предлагает владельцу следующий шаг.',
    note = 'OpenClaw работает только с доступными публичными источниками и соблюдает правила площадок. Он не рассылает сообщения и не меняет данные автоматически: любое обращение к потенциальному клиенту, внешняя отправка, изменение данных или техническое вмешательство выполняется только после подтверждения владельца.'
WHERE title = 'OpenClaw — AI-директор и центр управления бизнесом';